mapper.select:
select count(1)
from system_category
where id = #{categoryId}

mapper.update:
update budget_config
set budget_amount = #{budgetAmount}
where id = #{id}
  and user_id = #{userId}
  and is_deleted = 0

update budget_config
set budget_amount = #{budgetAmount},
    is_deleted = 0
where id = #{id}
  and user_id = #{userId}

mapper.select:
select
    b.category_id as categoryId,
    sum(b.amount) as usedAmount
from bill b

    b.user_id = #{userId}
    and b.is_deleted = 0
    and b.type = 2
    and b.record_time  >=  #{startTime}
    and b.record_time  <  #{endTime}

        and b.category_id in

            #{categoryId}



group by b.category_id
